const config = $('Configure Settings').first().json;
const record = $input.first().json;

const clientName = record['Client Name'] || 'Client';
const clientEmail = record['Client Email'] || '';
const lineItemsRaw = record['Line Items'] || '';
const taxRate = parseFloat(record['Tax Rate'] || '0') / 100;
const notes = record['Notes'] || '';
const quoteRef = `Q-${Date.now().toString(36).toUpperCase()}`;
const today = new Date().toISOString().split('T')[0];
const validDays = 30;
const validUntil = new Date(Date.now() + validDays * 86400000).toISOString().split('T')[0];

// Parse line items: "Description | Qty | Price" per line
const lineItems = lineItemsRaw.split('\n').filter(l => l.trim()).map(line => {
  const parts = line.split('|').map(p => p.trim());
  const description = parts[0] || 'Item';
  const qty = parseInt(parts[1] || '1');
  const price = parseFloat(parts[2] || '0');
  return { description, qty, price, total: qty * price };
});

const subtotal = lineItems.reduce((sum, item) => sum + item.total, 0);
const tax = subtotal * taxRate;
const grandTotal = subtotal + tax;

const itemRows = lineItems.map((item, i) =>
  `<tr>
    <td style="padding:12px 16px;border-bottom:1px solid #e5e7eb;">${i + 1}</td>
    <td style="padding:12px 16px;border-bottom:1px solid #e5e7eb;">${item.description}</td>
    <td style="padding:12px 16px;border-bottom:1px solid #e5e7eb;text-align:center;">${item.qty}</td>
    <td style="padding:12px 16px;border-bottom:1px solid #e5e7eb;text-align:right;">$${item.price.toFixed(2)}</td>
    <td style="padding:12px 16px;border-bottom:1px solid #e5e7eb;text-align:right;font-weight:600;">$${item.total.toFixed(2)}</td>
  </tr>`
).join('');

const html = `<!DOCTYPE html>
<html>
<head><meta charset="UTF-8"><style>
  body { font-family: 'Helvetica Neue', Arial, sans-serif; color: #1f2937; margin: 0; padding: 40px; }
  .header { display: flex; justify-content: space-between; margin-bottom: 40px; }
  .brand { font-size: 24px; font-weight: 800; color: ${config.brandColor}; }
  table { width: 100%; border-collapse: collapse; }
  th { background: ${config.brandColor}; color: white; padding: 12px 16px; text-align: left; font-size: 13px; text-transform: uppercase; letter-spacing: 0.5px; }
  th:nth-child(3), th:nth-child(4), th:nth-child(5) { text-align: center; }
  th:last-child { text-align: right; }
</style></head>
<body>
  <div class="header">
    <div>
      <div class="brand">${config.businessName}</div>
      <p style="color:#6b7280;font-size:13px;margin:4px 0;">${config.businessAddress}</p>
      <p style="color:#6b7280;font-size:13px;margin:4px 0;">${config.businessPhone} | ${config.businessEmail}</p>
    </div>
    <div style="text-align:right;">
      <h1 style="font-size:32px;color:${config.brandColor};margin:0;">QUOTE</h1>
      <p style="color:#6b7280;font-size:14px;margin:8px 0;">Ref: ${quoteRef}</p>
      <p style="color:#6b7280;font-size:14px;margin:4px 0;">Date: ${today}</p>
      <p style="color:#6b7280;font-size:14px;margin:4px 0;">Valid until: ${validUntil}</p>
    </div>
  </div>

  <div style="background:#f9fafb;border-radius:8px;padding:20px;margin-bottom:32px;">
    <p style="font-size:12px;text-transform:uppercase;letter-spacing:1px;color:#9ca3af;margin:0 0 8px 0;">Prepared for</p>
    <p style="font-size:18px;font-weight:700;margin:0;">${clientName}</p>
    <p style="color:#6b7280;font-size:14px;margin:4px 0;">${clientEmail}</p>
  </div>

  <table>
    <thead>
      <tr><th>#</th><th>Description</th><th>Qty</th><th>Unit Price</th><th style="text-align:right;">Total</th></tr>
    </thead>
    <tbody>${itemRows}</tbody>
  </table>

  <div style="display:flex;justify-content:flex-end;margin-top:24px;">
    <div style="width:280px;">
      <div style="display:flex;justify-content:space-between;padding:8px 0;border-bottom:1px solid #e5e7eb;">
        <span style="color:#6b7280;">Subtotal</span>
        <span>$${subtotal.toFixed(2)}</span>
      </div>
      <div style="display:flex;justify-content:space-between;padding:8px 0;border-bottom:1px solid #e5e7eb;">
        <span style="color:#6b7280;">Tax (${(taxRate * 100).toFixed(0)}%)</span>
        <span>$${tax.toFixed(2)}</span>
      </div>
      <div style="display:flex;justify-content:space-between;padding:12px 0;font-size:18px;font-weight:800;">
        <span>Total</span>
        <span style="color:${config.brandColor};">$${grandTotal.toFixed(2)}</span>
      </div>
    </div>
  </div>

  ${notes ? `<div style="margin-top:32px;padding:20px;background:#f9fafb;border-radius:8px;border-left:4px solid ${config.brandColor};"><p style="font-size:12px;text-transform:uppercase;letter-spacing:1px;color:#9ca3af;margin:0 0 8px 0;">Notes</p><p style="margin:0;color:#4b5563;">${notes}</p></div>` : ''}

  <div style="margin-top:48px;text-align:center;color:#9ca3af;font-size:12px;">
    <p>Thank you for considering ${config.businessName}.</p>
  </div>
</body>
</html>`;

return [{
  json: {
    html,
    clientName,
    clientEmail,
    quoteRef,
    grandTotal: grandTotal.toFixed(2),
    today,
    recordId: config.recordId,
    airtableBaseId: config.airtableBaseId,
    airtableTableName: config.airtableTableName,
    googleDriveFolderId: config.googleDriveFolderId,
    businessName: config.businessName
  }
}];
